/* HardFault 分析器 — 添加到项目中 */

void HardFault_Handler(void)
{
    uint32_t stacked_pc, stacked_lr, stacked_psr;

    __asm volatile (
        "TST   LR, #4\n"
        "ITE   EQ\n"
        "MRSEQ R0, MSP\n"
        "MRSNE R0, PSP\n"
        "MOV   %0, R0\n"
        : "=r" (stacked_pc)
    );

    /* 从栈中读取寄存器的值 */
    stacked_pc  = ((uint32_t *)stacked_pc)[6];  /* PC — 崩溃位置 */
    stacked_lr  = ((uint32_t *)stacked_pc)[5];  /* LR */
    stacked_psr = ((uint32_t *)stacked_pc)[7];  /* xPSR */

    printf("\n!!! HARDFAULT !!!\n");
    printf("  PC:  0x%08lX\n", stacked_pc);
    printf("  LR:  0x%08lX\n", stacked_lr);
    printf("  PSR: 0x%08lX\n", stacked_psr);
    printf("  CFSR: 0x%08lX (Configurable Fault)\n", SCB->CFSR);
    printf("  HFSR: 0x%08lX (Hard Fault)\n", SCB->HFSR);
    printf("  MMFAR: 0x%08lX (MemManage Fault Addr)\n", SCB->MMFAR);
    printf("  BFAR: 0x%08lX (Bus Fault Addr)\n", SCB->BFAR);

    /* 用 addr2line 定位崩溃位置 */
    printf("\n  Run: arm-none-eabi-addr2line -e build/firmware.elf 0x%08lX\n",
           stacked_pc);

    while (1); /* 停止执行 */
}

#include "profile.h"

/* 简易性能分析宏 */
#define PROFILE_START()  uint32_t _t0 = DWT->CYCCNT
#define PROFILE_END(tag) \
    do { \
        uint32_t _t1 = DWT->CYCCNT; \
        uint32_t _elapsed = _t1 - _t0; \
        printf("[PROFILE] %-20s: %8lu cycles (%6.2f us)\n", \
               tag, _elapsed, _elapsed / 480.0f); \
    } while(0)

/* 使用示例 */
void process_sensor_data(void)
{
    PROFILE_START();
    read_sensor_i2c();
    PROFILE_END("I2C Read");

    PROFILE_START();
    apply_kalman_filter();
    PROFILE_END("Kalman Filter");

    PROFILE_START();
    send_data_uart();
    PROFILE_END("UART Send");
}

