/* 将 ISR 放到 SRAM（DTCM）中执行以避免 Flash 等待 */
__attribute__((section(".ramfunc"), long_call))
void TIM2_IRQHandler(void)
{
    /* 时间关键的 ISR 代码 */
    TIM2->SR = ~TIM_SR_UIF;      /* 清除标志 */
    gpio_toggle(LED_PIN);         /* 翻转 LED */
}
